query CHANNEL_LIVES_QUERY($channel_name: String!) {
  channel(name: $channel_name) {
    id
    lives(isOnAir: true) {
      edges {
        node {
          id
          xid
          title
          thumbnailx60: thumbnailURL(size: "x60")
          thumbnailx120: thumbnailURL(size: "x120")
          thumbnailx240: thumbnailURL(size: "x240")
          thumbnailx720: thumbnailURL(size: "x720")
          aspectRatio
          isOnAir
          streamUrls {
            id
            hls
            __typename
          }
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
}

query ProfileRendererQuery($username: String!, $avatarSizes: [UserAvatarResizeImageSize!]) {
  profile: userByUsername(username: $username) {
    id
    legacyId
    userType: type
    username
    firstName
    displayName
    registeredAt
    canonicalPath
    isFeaturedPhotographer
    isBlockedByMe
    winnerCount
    crownFlag
    latestWinAt
    originalAvatar: avatar {
      images {
        url
        id
      }
      id
    }
    avatar {
      ...ProfileAvatarRefetchContainer_avatar_2v4paw
      id
    }
    badges {
      badge
    }
    userProfile {
      username
      firstname
      lastname
      state
      country
      city
      about
      id
    }
    userSetting {
      firstnameVisible
      locationVisible
      id
    }
    socialMedia {
      website
      twitter
      instagram
      facebook
      id
    }
    socialMediaItems {
      name
      value
      visible
      id
    }
    coverPhotoUrl
    followedBy {
      totalCount
      isFollowedByMe
    }
    followingUsers {
      totalCount
    }
    membership {
      expiryDate
      membershipTier: tier
      photoUploadQuota
      refreshPhotoUploadQuotaAt
      paymentStatus
      id
    }
    profileTabs {
      tabs {
        name
        visible
        count
      }
    }
    ...EditCover_cover
    ...EditProfileCover_cover
    photoStats {
      likeCount
      viewCount
    }
    portfolio {
      id
      status
      userDisabled
    }
  }
}

fragment EditCover_cover on User {
  coverPhotoUrl
}

fragment EditProfileCover_cover on User {
  coverPhotoUrl
}

fragment ProfileAvatarRefetchContainer_avatar_2v4paw on UserAvatar {
  id
  images(sizes: $avatarSizes) {
    size
    url
    id
  }
}
